// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract AellokSovereignMesh {
    uint256 public constant BURN_RATIO = 1000;
    uint256 public constant COB_INCENTIVE = 39;
    mapping(address => uint256) public sov2Balances;
    mapping(address => uint256) public cobUsageRights;

